import express from 'express';
import cors from 'cors';
import mysql from 'mysql2/promise';
import 'dotenv/config';

const app = express();
const port = 3001;

app.use(cors());
app.use(express.json());

let dbPool;
let currentDbName = '';

// Endpoint to test and set database connection
app.post('/api/connect', async (req, res) => {
    const { host, port, user, password, database } = req.body;
    if (!database) {
        return res.status(400).json({ message: 'Database name is required.' });
    }
    try {
        if (dbPool) {
            await dbPool.end();
        }
        dbPool = mysql.createPool({
            host,
            port,
            user,
            password,
            database,
            connectionLimit: 10,
            enableKeepAlive: true,
        });
        const connection = await dbPool.getConnection();
        connection.release();
        currentDbName = database;
        res.status(200).json({ message: 'Connection successful' });
    } catch (error) {
        dbPool = null;
        currentDbName = '';
        console.error('Database connection failed:', error);
        res.status(500).json({ message: 'Database connection failed', error: error.message });
    }
});

// Endpoint to fetch metrics
app.get('/api/metrics', async (req, res) => {
    if (!dbPool) {
        return res.status(400).json({ message: 'Database not connected' });
    }

    try {
        const connection = await dbPool.getConnection();

        const [globalStatus] = await connection.query("SHOW GLOBAL STATUS;");
        const [variables] = await connection.query("SHOW VARIABLES;");
        const [processList] = await connection.query("SELECT * FROM information_schema.PROCESSLIST WHERE command != 'Sleep' AND time > 1 ORDER BY time DESC LIMIT 5;");

        const statusMap = new Map(globalStatus.map(row => [row.Variable_name, row.Value]));
        const varMap = new Map(variables.map(row => [row.Variable_name, row.Value]));

        // Replication Lag
        let replicationLag = 0;
        try {
            const [slaveStatus] = await connection.query("SHOW SLAVE STATUS;");
            if (slaveStatus.length > 0 && slaveStatus[0].Seconds_Behind_Master) {
                replicationLag = slaveStatus[0].Seconds_Behind_Master;
            }
        } catch (e) {
            // Not a replica or error, lag is 0
        }

        const totalPages = parseFloat(statusMap.get('Innodb_buffer_pool_pages_total')) || 0;
        const freePages = parseFloat(statusMap.get('Innodb_buffer_pool_pages_free')) || 0;
        const bufferPoolUsage = totalPages > 0 ? ((totalPages - freePages) / totalPages) * 100 : 0;

        const uptime = parseInt(statusMap.get('Uptime'), 10);
        const totalQueries = parseInt(statusMap.get('Queries'), 10);

        const metrics = {
            uptime,
            queriesPerSecond: uptime > 0 ? Math.round(totalQueries / uptime) : 0,
            slowQueries: parseInt(statusMap.get('Slow_queries'), 10),
            activeConnections: parseInt(statusMap.get('Threads_connected'), 10),
            maxConnections: parseInt(varMap.get('max_connections'), 10),
            threadsConnected: parseInt(statusMap.get('Threads_connected'), 10),
            cpuUtilization: 15 + Math.random() * 50, // Simulated
            memoryUsage: 25 + Math.random() * 40, // Simulated
            bufferPoolUsage: parseFloat(bufferPoolUsage.toFixed(1)),
            replicationLag: replicationLag,
            topSlowQueries: processList.map(p => ({
                id: p.ID,
                time: p.TIME,
                query: p.INFO || 'N/A',
                user: p.USER,
                host: p.HOST
            })),
            databaseName: currentDbName,
        };

        connection.release();
        res.json(metrics);

    } catch (error) {
        console.error('Error fetching metrics:', error);
        res.status(500).json({ message: 'Error fetching metrics', error: error.message });
    }
});

// Endpoint to fetch InnoDB engine status
app.get('/api/innodb-status', async (req, res) => {
    if (!dbPool) {
        return res.status(400).json({ message: 'Database not connected' });
    }

    try {
        const connection = await dbPool.getConnection();
        const [rows] = await connection.query("SHOW ENGINE INNODB STATUS;");
        connection.release();

        if (rows && rows.length > 0) {
            // MySQL returns a row with Type, Name, and Status columns
            res.json({ status: rows[0].Status });
        } else {
            res.status(404).json({ message: 'No InnoDB status found' });
        }
    } catch (error) {
        console.error('Error fetching InnoDB status:', error);
        res.status(500).json({ message: 'Error fetching InnoDB status', error: error.message });
    }
});

app.listen(port, () => {
    console.log(`Server running at http://localhost:${port}`);
    console.log("Ensure you have a .env file with your API_KEY.");
});

export type ViewMode = 'dashboard' | 'innodb';

export interface SlowQuery {
  id: number;
  time: number;
  query: string;
  user: string;
  host: string;
}

export interface MySQLMetrics {
  uptime: number;
  queriesPerSecond: number;
  slowQueries: number;
  activeConnections: number;
  maxConnections: number;
  threadsConnected: number;
  cpuUtilization: number;
  memoryUsage: number;
  bufferPoolUsage: number;
  replicationLag: number;
  topSlowQueries: SlowQuery[];
  databaseName: string;
}

export interface TimeSeriesDataPoint {
  time: string;
  qps: number;
  cpu: number;
}

export interface InnoDBStatusSection {
  title: string;
  content: string;
}

import { MySQLMetrics } from '../types';

const API_BASE_URL = 'http://localhost:3001';

export const connectToDatabase = async (credentials: { host: string, port: string, user: string, password?: string, database: string }) => {
    const response = await fetch(`${API_BASE_URL}/api/connect`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(credentials),
    });

    if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || 'Failed to connect to the database');
    }
    return await response.json();
};


export const fetchMetrics = async (): Promise<MySQLMetrics> => {
    const response = await fetch(`${API_BASE_URL}/api/metrics`);
    if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || 'Failed to fetch metrics');
    }
    return await response.json();
};

export const fetchInnoDBStatus = async (): Promise<{ status: string }> => {
    const response = await fetch(`${API_BASE_URL}/api/innodb-status`);
    if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || 'Failed to fetch InnoDB status');
    }
    return await response.json();
};

