import React, { useState, useEffect } from 'react';
import { XIcon, DatabaseIcon, TrashIcon, PlusIcon, CheckIcon } from './icons';
import { ConnectionStatus } from '../App';
import { connectToDatabase } from '../services/apiService';
import { DbConnection } from '../types';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  activeConnectionId: string | null;
  onSelectConnection: (connection: DbConnection) => void;
  setConnectionStatus: (status: ConnectionStatus) => void;
  setConnectionError: (error: string) => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ 
  isOpen, 
  onClose, 
  activeConnectionId,
  onSelectConnection,
  setConnectionStatus, 
  setConnectionError 
}) => {
  const [connections, setConnections] = useState<DbConnection[]>([]);
  const [showAddForm, setShowAddForm] = useState(false);

  // Form State
  const [nickname, setNickname] = useState('');
  const [host, setHost] = useState('localhost');
  const [port, setPort] = useState('3306');
  const [user, setUser] = useState('root');
  const [password, setPassword] = useState('');
  const [database, setDatabase] = useState('');

  const [isConnecting, setIsConnecting] = useState(false);
  const [formError, setFormError] = useState('');

  // Load connections from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('mysql_orion_connections');
    if (saved) {
      try {
        setConnections(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved connections", e);
      }
    }
  }, []);

  // Save connections to localStorage
  const saveToStorage = (updatedList: DbConnection[]) => {
    localStorage.setItem('mysql_orion_connections', JSON.stringify(updatedList));
    setConnections(updatedList);
  };

  if (!isOpen) return null;

  const handleAddConnection = async () => {
    if (!database || !host || !user || !nickname) {
      setFormError('Nickname, Host, User, and Database are required.');
      return;
    }

    setFormError('');
    setIsConnecting(true);

    try {
      // Test connection first
      await connectToDatabase({ host, port, user, password, database });

      const newConn: DbConnection = {
        id: crypto.randomUUID(),
        nickname,
        host,
        port,
        user,
        password,
        database
      };

      const updatedList = [...connections, newConn];
      saveToStorage(updatedList);

      // Reset form
      setNickname('');
      setHost('localhost');
      setPort('3306');
      setUser('root');
      setPassword('');
      setDatabase('');
      setShowAddForm(false);

      // Auto-select the new connection
      onSelectConnection(newConn);
    } catch (err: any) {
      setFormError(err.message || 'Failed to connect. Check credentials.');
    } finally {
      setIsConnecting(false);
    }
  };

  const deleteConnection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const updatedList = connections.filter(c => c.id !== id);
    saveToStorage(updatedList);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-md" aria-modal="true" role="dialog">
      <div className="relative bg-slate-900 border border-slate-700 rounded-xl shadow-2xl w-full max-w-2xl m-4 flex flex-col max-h-[90vh]">
        <div className="flex items-center justify-between p-5 border-b border-slate-800">
          <div className="flex items-center gap-3">
            <DatabaseIcon className="w-6 h-6 text-cyan-400" />
            <h2 className="text-xl font-bold font-orbitron text-cyan-400">Database Manager</h2>
          </div>
          <button onClick={onClose} className="text-slate-500 hover:text-white transition-colors" disabled={isConnecting}>
            <XIcon className="w-6 h-6" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
          {/* Connection List Section */}
          {!showAddForm && (
            <div className="space-y-4">
              <div className="flex items-center justify-between mb-2">
                <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Saved Clusters</h3>
                <button 
                  onClick={() => setShowAddForm(true)}
                  className="flex items-center gap-2 text-xs font-bold text-cyan-400 hover:text-cyan-300 transition-colors py-1 px-3 rounded-md bg-cyan-400/10 border border-cyan-400/20"
                >
                  <PlusIcon className="w-3.5 h-3.5" /> ADD NEW
                </button>
              </div>

              {connections.length === 0 ? (
                <div className="text-center py-12 bg-slate-800/30 border border-dashed border-slate-700 rounded-xl">
                  <p className="text-slate-500 italic">No saved connections found.</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  {connections.map((conn) => (
                    <div 
                      key={conn.id}
                      onClick={() => onSelectConnection(conn)}
                      className={`group relative p-4 rounded-xl border cursor-pointer transition-all duration-300 ${
                        activeConnectionId === conn.id 
                        ? 'bg-cyan-500/10 border-cyan-500 ring-1 ring-cyan-500/50' 
                        : 'bg-slate-800/50 border-slate-700 hover:border-slate-500 hover:bg-slate-800'
                      }`}
                    >
                      <div className="flex items-start justify-between">
                        <div className="flex-1 min-w-0 pr-6">
                          <h4 className="font-bold text-slate-100 truncate flex items-center gap-2">
                            {conn.nickname}
                            {activeConnectionId === conn.id && <CheckIcon className="w-4 h-4 text-cyan-400 shrink-0" />}
                          </h4>
                          <p className="text-xs text-slate-400 truncate mt-1">{conn.user}@{conn.host}:{conn.port}</p>
                          <p className="text-xs text-cyan-500/80 font-mono mt-0.5 truncate uppercase">{conn.database}</p>
                        </div>
                        <button 
                          onClick={(e) => deleteConnection(conn.id, e)}
                          className="text-slate-600 hover:text-red-400 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <TrashIcon className="w-4 h-4" />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Add Form Section */}
          {showAddForm && (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Configure New Connection</h3>
                <button onClick={() => setShowAddForm(false)} className="text-xs text-slate-500 hover:text-slate-300">Back to list</button>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 bg-slate-800/40 p-5 rounded-xl border border-slate-700">
                <div className="sm:col-span-2">
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1.5">Connection Nickname</label>
                  <input 
                    type="text" 
                    placeholder="e.g. Production Main"
                    value={nickname} 
                    onChange={e => setNickname(e.target.value)}
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-100 focus:ring-2 focus:ring-cyan-500 outline-none transition" 
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1.5">Hostname / IP</label>
                  <input 
                    type="text" 
                    value={host} 
                    onChange={e => setHost(e.target.value)}
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-100 focus:ring-2 focus:ring-cyan-500 outline-none transition" 
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1.5">Port</label>
                  <input 
                    type="text" 
                    value={port} 
                    onChange={e => setPort(e.target.value)}
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-100 focus:ring-2 focus:ring-cyan-500 outline-none transition" 
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1.5">User</label>
                  <input 
                    type="text" 
                    value={user} 
                    onChange={e => setUser(e.target.value)}
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-100 focus:ring-2 focus:ring-cyan-500 outline-none transition" 
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1.5">Password</label>
                  <input 
                    type="password" 
                    value={password} 
                    onChange={e => setPassword(e.target.value)}
                    placeholder="••••••••"
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-100 focus:ring-2 focus:ring-cyan-500 outline-none transition" 
                  />
                </div>
                <div className="sm:col-span-2">
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1.5">Database Name (Required)</label>
                  <input 
                    type="text" 
                    value={database} 
                    onChange={e => setDatabase(e.target.value)}
                    placeholder="my_database"
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-100 focus:ring-2 focus:ring-cyan-500 outline-none transition border-cyan-500/30 shadow-[0_0_10px_rgba(6,182,212,0.05)]" 
                  />
                </div>
              </div>

              {formError && (
                <div className="mt-4 p-3 bg-red-900/30 border border-red-500/50 rounded-lg flex items-start gap-3">
                  <div className="text-red-400 mt-0.5">⚠️</div>
                  <p className="text-sm text-red-200">{formError}</p>
                </div>
              )}
            </div>
          )}
        </div>

        <div className="p-5 border-t border-slate-800 bg-slate-900/50 flex justify-end gap-3 rounded-b-xl">
          {showAddForm ? (
            <>
              <button 
                onClick={() => setShowAddForm(false)} 
                disabled={isConnecting}
                className="px-5 py-2 text-slate-400 hover:text-white transition-colors"
              >
                Cancel
              </button>
              <button 
                onClick={handleAddConnection}
                disabled={isConnecting}
                className="bg-cyan-600 hover:bg-cyan-500 text-white font-bold py-2 px-8 rounded-lg shadow-lg shadow-cyan-900/20 flex items-center gap-2 disabled:opacity-50"
              >
                {isConnecting ? (
                  <>
                    <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin"></div>
                    Testing...
                  </>
                ) : 'Test & Save Cluster'}
              </button>
            </>
          ) : (
            <button 
              onClick={onClose}
              className="px-6 py-2 bg-slate-800 hover:bg-slate-700 text-slate-100 rounded-lg transition-colors border border-slate-700"
            >
              Close
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default SettingsModal;

import React, { useState } from 'react';
import Dashboard from './components/Dashboard';
import Header from './components/Header';
import SettingsModal from './components/SettingsModal';
import InnoDBStatusPage from './components/InnoDBStatusPage';
import { ViewMode, DbConnection } from './types';
import { connectToDatabase } from './services/apiService';

export type ConnectionStatus = 'disconnected' | 'connecting' | 'connected' | 'error';

const App: React.FC = () => {
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState<ConnectionStatus>('disconnected');
  const [connectionError, setConnectionError] = useState('');
  const [databaseName, setDatabaseName] = useState('');
  const [viewMode, setViewMode] = useState<ViewMode>('dashboard');
  const [activeConnectionId, setActiveConnectionId] = useState<string | null>(null);

  const handleSelectConnection = async (conn: DbConnection) => {
    setConnectionStatus('connecting');
    setActiveConnectionId(conn.id);
    setIsSettingsOpen(false); // Close modal on select

    try {
      await connectToDatabase({
        host: conn.host,
        port: conn.port,
        user: conn.user,
        password: conn.password,
        database: conn.database
      });
      setConnectionStatus('connected');
      setDatabaseName(conn.database);
    } catch (err: any) {
      setConnectionError(err.message || 'Failed to reconnect');
      setConnectionStatus('error');
    }
  };

  return (
    <div className="bg-slate-950 min-h-screen text-slate-200">
      <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,')]"></div>
      <main className="relative container mx-auto p-4 sm:p-6 lg:p-8">
        <Header 
          onSettingsClick={() => setIsSettingsOpen(true)} 
          connectionStatus={connectionStatus}
          databaseName={databaseName}
          viewMode={viewMode}
          setViewMode={setViewMode}
        />

        {viewMode === 'dashboard' ? (
          <Dashboard 
            connectionStatus={connectionStatus} 
            connectionError={connectionError}
            onConnectClick={() => setIsSettingsOpen(true)}
            setDatabaseName={setDatabaseName}
          />
        ) : (
          <InnoDBStatusPage 
            connectionStatus={connectionStatus}
            onConnectClick={() => setIsSettingsOpen(true)}
          />
        )}
      </main>
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)}
        activeConnectionId={activeConnectionId}
        onSelectConnection={handleSelectConnection}
        setConnectionStatus={setConnectionStatus}
        setConnectionError={setConnectionError}
      />
    </div>
  );
};

export default App;

